INSERT INTO public.youtube_video_summaries (id, channel_name, collected_at, created_at, detail_summary_text, is_recommended_channel, published_at, summary_text, thumbnail_url, video_id, video_title, video_url, channel_id, language, transcript_text, transcript_type) VALUES (15, '김짠부', '2026-05-08 12:45:12.541505', '2026-05-08 12:48:28.851773', '## 목돈 보관, 어디에 넣어야 할까

1천만 원 이상의 목돈을 보관할 때 일반 통장에 두기는 아깝고, S&P 500 같은 장기 투자는 단기간에 손실 위험이 있어 부담스러운 경우가 많습니다. 이런 경우 단기 채권 ETF가 대안이 될 수 있습니다.

## 단기 채권 ETF란

ETF는 여러 투자 상품을 묶어놓은 ''투자 도시락''으로, 증권사 앱에서 주식처럼 쉽게 매매할 수 있습니다. 단기 채권 ETF는 국채, 은행채 등 안전한 채권들을 모아놓은 상품입니다. ''단기''는 만기가 1년 이내로 짧아 가격 변동이 적다는 의미이며, ''채권''은 국가나 은행이 발행한 차용증으로 안전성이 높습니다.

## 추천 상품과 예상 수익

코덱스 단기채권 플러스, 타이거 단기채권 액티브, 라이즈 단기채권 알파 등이 대표적입니다. 연 3% 수익률 기준으로 1천만 원은 약 25만 원, 3천만 원은 약 76만 원, 5천만 원은 약 127만 원의 이자를 받을 수 있습니다. 이자 수익에는 15.4% 세금이 부과되지만, ISA 계좌에서 매수하면 일반형 200만 원, 서민형 400만 원까지 비과세 혜택을 받을 수 있습니다.

## 파킹통장과의 비교

저축은행 파킹통장은 소액(50만 원 이하)에는 높은 금리를 제공하지만, 500만 원을 초과하면 금리가 급격히 낮아집니다. 반면 단기 채권 ETF는 금액이 클수록 유리하며, 복잡한 우대조건 없이 증권사 앱에서 간단히 매수할 수 있다는 장점이 있습니다. 소액 비상금은 파킹통장에, 당장 쓸 일은 없지만 3년 이상 묶어두기 어려운 목돈은 단기 채권 ETF에 보관하는 방식이 효율적입니다.', true, '2026-04-29 10:00:50', '1천만 원 이상 목돈은 단기 채권 ETF에 넣으면 파킹통장보다 이자를 더 받을 수 있대요
단기 채권 ETF는 국채나 은행채로 구성돼서 안전하고 증권사 앱에서 주식처럼 쉽게 살 수 있어요
